export class QuoteDetailComponent {
  constructor(route, quoteService, authService, userService, permissionService, ngZone) {
    this.route = route;
    this.quoteService = quoteService;
    this.authService = authService;
    this.userService = userService;
    this.permissionService = permissionService;
    this.ngZone = ngZone;
    this.quote = null;
    this.loading = true;
    this.error = '';
    this.quoters = [];
    this.suppliers = [];
    this.editMode = false;
    this.quoteForm = {};
    this.uploading = false;
    this.uploadProgress = 0;
    this.assigning = false;
    this.selectedSupplierId = '';
    this.selectedFiles = [];
  }
  ngOnInit() {
    const quoteId = this.route.snapshot.paramMap.get('id');
    if (quoteId) {
      this.loadQuote(quoteId);
      if (this.authService.hasRole('admin')) {
        this.loadQuoters();
      }
      if (this.authService.hasRole('quoter') || this.authService.hasRole('admin')) {
        this.loadSuppliers();
      }
    }
  }
  loadQuote(id) {
    this.loading = true;
    this.quoteService.getQuoteById(id).subscribe({
      next: quote => {
        this.quote = quote;
        this.quoteForm = {
          ...quote
        };
        this.loading = false;
        console.log('服务器返回 supplierFile.originalName =', this.quote?.supplierFile?.originalName);
      },
      error: () => {
        this.error = '加载询价单失败';
        this.loading = false;
      }
    });
  }
  loadQuoters() {
    this.userService.getAllUsers().subscribe({
      next: users => {
        this.quoters = users.filter(user => user.role === 'quoter' && user.isActive);
      },
      error: error => {
        console.error('加载报价员失败:', error);
      }
    });
  }
  loadSuppliers() {
    this.userService.getSuppliers().subscribe({
      next: suppliers => {
        this.suppliers = suppliers;
      },
      error: error => {
        console.error('加载供应商列表失败:', error);
      }
    });
  }
  // 获取指定类型的文件列表
  getFiles(fileType) {
    if (!this.quote) return [];
    // 优先使用新的多文件字段，向后兼容旧的单文件字段
    switch (fileType) {
      case 'customer':
        return this.quote.customerFiles && this.quote.customerFiles.length > 0 ? this.quote.customerFiles : this.quote.customerFile ? [this.quote.customerFile] : [];
      case 'supplier':
        return this.quote.supplierFiles && this.quote.supplierFiles.length > 0 ? this.quote.supplierFiles : this.quote.supplierFile ? [this.quote.supplierFile] : [];
      case 'quoter':
        return this.quote.quoterFiles && this.quote.quoterFiles.length > 0 ? this.quote.quoterFiles : this.quote.quoterFile ? [this.quote.quoterFile] : [];
      default:
        return [];
    }
  }
  // 检查是否有指定类型的文件
  hasFiles(fileType) {
    return this.getFiles(fileType).length > 0;
  }
  downloadFile(fileType, fileIndex) {
    if (!this.quote || this.uploading) return;
    // 根据用户角色和询价单状态决定下载哪个文件
    const user = this.authService.getCurrentUser();
    if (!user) return;
    let actualFileType = fileType;
    if (user.role === 'customer') {
      // 客户：未报价时下载原文件，已报价时下载报价文件
      actualFileType = this.quote.status === 'quoted' ? 'quoter' : 'customer';
    }
    this.quoteService.downloadFile(this.quote._id, actualFileType, fileIndex).subscribe({
      next: blob => {
        this.ngZone.run(() => {
          try {
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.style.display = 'none';
            document.body.appendChild(a);
            // 获取文件名
            const files = this.getFiles(actualFileType);
            const targetFile = fileIndex !== undefined && files[fileIndex] ? files[fileIndex] : files[0];
            const originalName = targetFile?.originalName || `${this.quote?.quoteNumber}_${actualFileType}.xlsx`;
            a.download = originalName;
            // 使用setTimeout确保DOM操作完成
            setTimeout(() => {
              a.click();
              // 延迟清理URL和DOM元素
              setTimeout(() => {
                document.body.removeChild(a);
                window.URL.revokeObjectURL(url);
              }, 100);
            }, 0);
          } catch (error) {
            console.error('下载文件处理失败:', error);
            alert('下载文件处理失败');
          }
        });
      },
      error: error => {
        this.ngZone.run(() => {
          console.error('下载文件失败:', error);
          alert('下载文件失败');
        });
      }
    });
  }
  // 批量下载文件
  downloadFilesBatch(fileType) {
    if (!this.quote || this.uploading) return;
    // 根据用户角色和询价单状态决定下载哪个文件
    const user = this.authService.getCurrentUser();
    if (!user) return;
    let actualFileType = fileType;
    if (user.role === 'customer') {
      // 客户：未报价时下载原文件，已报价时下载报价文件
      actualFileType = this.quote.status === 'quoted' ? 'quoter' : 'customer';
    }
    this.quoteService.downloadFilesBatch(this.quote._id, actualFileType).subscribe({
      next: blob => {
        this.ngZone.run(() => {
          try {
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.style.display = 'none';
            document.body.appendChild(a);
            // 生成ZIP文件名
            const zipFileName = `${this.quote?.quoteNumber}_${this.getFileTypeName(actualFileType)}文件.zip`;
            a.download = zipFileName;
            // 使用setTimeout确保DOM操作完成
            setTimeout(() => {
              a.click();
              // 延迟清理URL和DOM元素
              setTimeout(() => {
                document.body.removeChild(a);
                window.URL.revokeObjectURL(url);
              }, 100);
            }, 0);
          } catch (error) {
            console.error('批量下载文件处理失败:', error);
            alert('批量下载文件处理失败');
          }
        });
      },
      error: error => {
        this.ngZone.run(() => {
          console.error('批量下载文件失败:', error);
          alert('批量下载文件失败');
        });
      }
    });
  }
  // 获取文件类型的中文名称
  getFileTypeName(fileType) {
    switch (fileType) {
      case 'customer':
        return '客户询价';
      case 'supplier':
        return '供应商报价';
      case 'quoter':
        return '最终报价';
      default:
        return '文件';
    }
  }
  onFilesSelected(event) {
    const files = Array.from(event.target.files);
    if (files.length === 0) return;
    // 检查用户权限和状态
    const user = this.authService.getCurrentUser();
    if (user?.role === 'customer' && this.quote?.status !== 'pending') {
      alert('询价单不是待处理状态，无法选择文件');
      event.target.value = '';
      return;
    }
    if (user?.role === 'supplier' && !['in_progress', 'rejected'].includes(this.quote?.status || '')) {
      alert('询价单不是处理中或被拒绝状态，无法选择文件');
      event.target.value = '';
      return;
    }
    if ((user?.role === 'quoter' || user?.role === 'admin') && !['pending', 'supplier_quoted', 'in_progress'].includes(this.quote?.status || '')) {
      alert('询价单当前状态不允许上传最终报价文件');
      event.target.value = '';
      return;
    }
    // 检查所有文件类型和大小
    const validFiles = [];
    for (const file of files) {
      // 检查文件类型
      if (!file.name.endsWith('.xlsx') && !file.name.endsWith('.xls')) {
        alert(`文件 "${file.name}" 不是Excel文件，请选择 .xlsx 或 .xls 文件`);
        continue;
      }
      // 检查文件大小 (10MB限制)
      if (file.size > 10 * 1024 * 1024) {
        alert(`文件 "${file.name}" 大小超过10MB限制`);
        continue;
      }
      // 检查是否已经选择了同名文件
      const existingFile = this.selectedFiles.find(f => f.name === file.name);
